@startuml
skinparam classAttributeIconSize 0

interface Vehiculo {
  marca:string
  modelo:string
  velocidadMax:number
  --
  encender():void
  apagar():void
  acelerar():void
  frenar():void
}

interface Recargable {
  autonomia:string
  --
  cargar(number):void
  descargar(number):void
}

interface VehiculoRecargable

class BiciElectrica {
  pedalear():void
}

class AutoElectrico {
  manejoAutonomo():void
}

class MonopatinElectrico {
  ajustarAltura():void
  plegar():void
}

VehiculoRecargable -|> Vehiculo
VehiculoRecargable -|> Recargable

BiciElectrica ..|> VehiculoRecargable
AutoElectrico ..|> VehiculoRecargable
MonopatinElectrico ..|> VehiculoRecargable
@enduml
